namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentCode { get; set; } = string.Empty;
    public string CourseNumber { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }

    public string FullCode => $"{DepartmentCode} {CourseNumber}";
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 4, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and fundamental forces." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has authored two textbooks on Python programming.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques (sorting, searching, dynamic programming).", Credits = 4, Schedule = "TTh 10:30–11:45 AM", InstructorName = "Dr. James Liu", InstructorBio = "Dr. Liu's research focuses on algorithm optimization. He holds a PhD from MIT and has published over 40 papers.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "350", Title = "Database Systems", Description = "Design and implementation of relational database systems. Covers SQL, normalization, indexing, and transaction management.", Credits = 3, Schedule = "MWF 1:00–1:50 PM", InstructorName = "Dr. Maria Gonzalez", InstructorBio = "Dr. Gonzalez worked at Oracle for 10 years before joining academia. She specializes in distributed database systems.", IsFeatured = false },
            new() { Id = 4, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "MWF 8:00–8:50 AM", InstructorName = "Dr. Robert Taylor", InstructorBio = "Dr. Taylor is an award-winning educator with a passion for making calculus accessible to all students.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations with applications.", Credits = 3, Schedule = "TTh 2:00–3:15 PM", InstructorName = "Dr. Emily Park", InstructorBio = "Dr. Park researches applied linear algebra and has consulting experience with aerospace companies.", IsFeatured = false },
            new() { Id = 6, DepartmentId = 3, DepartmentCode = "ENG", CourseNumber = "101", Title = "College Composition", Description = "Develop skills in academic writing, critical reading, and argumentation. Emphasis on clear, effective prose.", Credits = 3, Schedule = "MWF 10:00–10:50 AM", InstructorName = "Prof. David Kim", InstructorBio = "Prof. Kim is a published novelist and essayist who brings creative energy to academic writing instruction.", IsFeatured = false },
            new() { Id = 7, DepartmentId = 3, DepartmentCode = "ENG", CourseNumber = "250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present, exploring themes of identity, freedom, and democracy.", Credits = 3, Schedule = "TTh 11:00 AM–12:15 PM", InstructorName = "Dr. Angela Brooks", InstructorBio = "Dr. Brooks specializes in 20th-century American fiction and has received multiple teaching excellence awards.", IsFeatured = true },
            new() { Id = 8, DepartmentId = 4, DepartmentCode = "PHYS", CourseNumber = "101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions with hands-on experiments.", Credits = 4, Schedule = "MWF 11:00–11:50 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres conducts research in experimental particle physics and is passionate about physics education.", IsFeatured = false },
            new() { Id = 9, DepartmentId = 4, DepartmentCode = "PHYS", CourseNumber = "301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, operators, and applications to atomic systems.", Credits = 3, Schedule = "MWF 2:00–2:50 PM", InstructorName = "Dr. Lisa Wang", InstructorBio = "Dr. Wang is a theoretical physicist whose research bridges quantum information and condensed matter physics.", IsFeatured = false },
            new() { Id = 10, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "101", Title = "World Civilizations", Description = "Survey of major world civilizations from antiquity to 1500 CE, examining political, social, and cultural developments.", Credits = 3, Schedule = "TTh 9:00–10:15 AM", InstructorName = "Dr. William Harris", InstructorBio = "Dr. Harris is an archaeologist and historian who has led excavations in the Mediterranean region.", IsFeatured = false },
            new() { Id = 11, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "220", Title = "Modern European History", Description = "Europe from the Enlightenment to the present day, covering revolutions, world wars, and contemporary challenges.", Credits = 3, Schedule = "MWF 3:00–3:50 PM", InstructorName = "Dr. Katherine Schmidt", InstructorBio = "Dr. Schmidt is a specialist in 20th-century European history and has authored three books on Cold War diplomacy.", IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? query, int? departmentId)
    {
        var results = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            results = results.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(query))
        {
            var q = query.Trim().ToLowerInvariant();
            results = results.Where(c =>
                c.Title.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.FullCode.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(q, StringComparison.OrdinalIgnoreCase));
        }

        return results.ToList();
    }

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In production, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && GetCourse(request.CourseId) != null;
    }
}

