@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome to the course catalog. Browse departments, explore courses, and submit your enrollment request.</p>

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.FullCode</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Credits credits · @course.InstructorName</p>
                    <a href="courses/@course.Id" class="card-link">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name (@dept.Code)</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="courses?departmentId=@dept.Id" class="card-link">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="query" value="@Query"
               placeholder="Search by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <label for="department" class="form-label">Department</label>
        <select class="form-select" id="department" name="departmentId">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.FullCode</td>
                    <td>@course.Title</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td>@course.Schedule</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Query { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.SearchCourses(Query, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
