            <h2>Schedule</h2>
            <p>@course.Schedule</p>

            <h2>Instructor</h2>
            <h5>@course.InstructorName</h5>
            <p>@course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Info</h5>
                    <ul class="list-unstyled">
                        <li><strong>Code:</strong> @course.FullCode</li>
                        <li><strong>Credits:</strong> @course.Credits</li>
                        <li><strong>Schedule:</strong> @course.Schedule</li>
                        <li><strong>Instructor:</strong> @course.InstructorName</li>
                    </ul>
                    <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to submit an enrollment request.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Success!</strong> Your enrollment request has been submitted. You will receive a confirmation via your student email.
    </div>
    <a href="courses" class="btn btn-primary">Browse More Courses</a>
}
else
{
    if (error)
    {
        <div class="alert alert-danger">
            Please fill in all required fields and select a valid course.
        </div>
    }

    <form method="post" @formname="enrollment" @onsubmit="HandleSubmit" class="col-md-6">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                   value="@Model.StudentName" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
            <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                   value="@Model.StudentId" required placeholder="e.g., STU-12345" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
            <select class="form-select" id="courseId" name="Model.CourseId" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">
                        @course.FullCode — @course.Title (@course.Credits cr)
                    </option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
        <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </form>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private bool error;

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        if (Catalog.SubmitEnrollmentRequest(Model))
        {
            submitted = true;
        }
        else
        {
            error = true;
        }
    }
}

